// Format waitlist response con message legible para el LLM
const result = $input.first().json;
const isSuccess = result.success === true;
const position  = result.data?.position || result.data?.waitlist_position || null;

return [{
  json: {
    success: isSuccess,
    message: isSuccess
      ? `Fuiste añadido a la lista de espera${position ? ' en posición #' + position : ''}. Te avisaremos por email cuando haya un turno disponible.`
      : (result.error_message || 'No se pudo agregar a la lista de espera.'),
    error_code:    isSuccess ? null : 'DAL_ERROR',
    error_message: isSuccess ? null : (result.error_message || 'Waitlist join failed'),
    data: result.data || null,
    _meta: { source: 'DB_Join_Waitlist', timestamp: new Date().toISOString(), version: '3.0.0' }
  }
}];

// 📤 STANDARD CONTRACT OUTPUT — Tool-compatible (v3.0.0)
// El AI Agent lee "message" como respuesta legible y "data" para detalles.
const result = $input.first()?.json || {};
const isSuccess = result.success !== false;

// Construir mensaje legible para el LLM
let message = result.message || result.data?.message || null;
if (!message) {
  message = isSuccess
    ? 'Operación completada con éxito.'
    : (result.error_message || result.error_code || 'Error desconocido.');
}

return [{
  json: {
    success: isSuccess,
    message,
    error_code:    isSuccess ? null : (result.error_code    || 'UNKNOWN_ERROR'),
    error_message: isSuccess ? null : (result.error_message || message),
    data:          result.data || null,
    _meta: {
      source:    'DB_JOIN_WAITLIST',
      timestamp: new Date().toISOString(),
      version:   '3.0.0'
    }
  }
}];
